def gen(rng, size):
    n = rng.randint(1, max(1, size))
    arr = [rng.randint(-1000, 1000)]
    for _ in range(n - 1):
        arr.append(rng.randint(-1000, 1000) if rng.random() < 0.85 else None)
    return [arr]

