class Solution:
    def sumOfLeftLeaves(self, root):
        def walk(node, is_left):
            if node is None:
                return 0
            if node.left is None and node.right is None:
                return node.val if is_left else 0
            return walk(node.left, True) + walk(node.right, False)
        return walk(root, False)

